'use client';

import React, { useState } from 'react';
import { useAuth } from '../lib/auth';
import styles from './AuthModal.module.css';

interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose }) => {
  const { login } = useAuth();
  const [email, setEmail] = useState('');
  const [role, setRole] = useState<'buyer' | 'admin'>('buyer');
  const [isSubmitting, setIsSubmitting] = useState(false);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;
    setIsSubmitting(true);
    await login(email, role);
    setIsSubmitting(false);
    onClose();
  };

  const handleQuickLogin = async (selectedRole: 'buyer' | 'admin') => {
    setIsSubmitting(true);
    const mockEmail = selectedRole === 'admin' ? 'admin@stokiloo.com' : 'buyer@stokiloo.com';
    await login(mockEmail, selectedRole);
    setIsSubmitting(false);
    onClose();
  };

  return (
    <div className={styles.overlay} onClick={onClose}>
      <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
        <button className={styles.closeBtn} onClick={onClose} aria-label="Close modal">
          &times;
        </button>
        <h2 className={styles.title}>Welcome to Stokiloo</h2>
        <p className={styles.subtitle}>Sign in to manage your orders or stock inventory</p>

        <form onSubmit={handleSubmit} className={styles.form}>
          <div className={styles.inputGroup}>
            <label className={styles.label}>Email Address</label>
            <input
              type="email"
              className="input"
              placeholder="name@company.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div className={styles.inputGroup}>
            <label className={styles.label}>Select Role</label>
            <div className={styles.roleSelector}>
              <label className={`${styles.roleOption} ${role === 'buyer' ? styles.active : ''}`}>
                <input
                  type="radio"
                  name="role"
                  value="buyer"
                  checked={role === 'buyer'}
                  onChange={() => setRole('buyer')}
                />
                Buyer
              </label>
              <label className={`${styles.roleOption} ${role === 'admin' ? styles.active : ''}`}>
                <input
                  type="radio"
                  name="role"
                  value="admin"
                  checked={role === 'admin'}
                  onChange={() => setRole('admin')}
                />
                Administrator
              </label>
            </div>
          </div>

          <button type="submit" className="btn btn-primary" style={{ width: '100%' }} disabled={isSubmitting}>
            {isSubmitting ? 'Logging in...' : 'Continue with Email'}
          </button>
        </form>

        <div className={styles.divider}>
          <span>or Quick Login</span>
        </div>

        <div className={styles.quickActions}>
          <button className="btn btn-secondary" onClick={() => handleQuickLogin('buyer')} disabled={isSubmitting}>
            Login as Demo Buyer
          </button>
          <button className="btn btn-secondary" onClick={() => handleQuickLogin('admin')} disabled={isSubmitting}>
            Login as Demo Admin
          </button>
        </div>
      </div>
    </div>
  );
};
