'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { useAuth } from '../lib/auth';
import { useCart } from '../lib/cart';
import { getProducts } from '../lib/db';
import { Product } from '../lib/types';
import { AuthModal } from '../components/AuthModal';
import { CartDrawer } from '../components/CartDrawer';
import styles from './page.module.css';

export default function Home() {
  const { user, isAuthenticated, logout } = useAuth();
  const { addToCart, setIsCartOpen, totalItems } = useCart();

  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  // Load products on mount or search query change
  useEffect(() => {
    const fetchProducts = async () => {
      setLoading(true);
      try {
        const data = await getProducts(search);
        setProducts(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchProducts();
  }, [search]);

  return (
    <div className={styles.page}>
      {/* 1. Header Nav */}
      <header className="glass-nav">
        <div className={`container ${styles.navContainer}`}>
          <Link href="/" className={styles.logo}>
            Stokiloo<span>.</span>
          </Link>

          <div className={styles.searchWrapper}>
            <input
              type="text"
              placeholder="Search wholesale products (e.g. tees, chargers, avocado)..."
              className="input"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <div className={styles.navActions}>
            {isAuthenticated ? (
              <>
                {user?.role === 'admin' ? (
                  <Link href="/admin/orders" className="btn btn-outline">
                    Admin Panel
                  </Link>
                ) : (
                  <Link href="/dashboard" className="btn btn-outline">
                    My Orders
                  </Link>
                )}
                <span className={styles.userEmail}>{user?.email}</span>
                <button className="btn btn-secondary" onClick={logout}>
                  Sign Out
                </button>
              </>
            ) : (
              <button className="btn btn-primary" onClick={() => setIsAuthOpen(true)}>
                Sign In
              </button>
            )}

            <button className={styles.cartButton} onClick={() => setIsCartOpen(true)} aria-label="Open cart">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className={styles.cartIcon}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 10.5V6a3.75 3.75 0 1 0-7.5 0v4.5m11.356-1.993 1.263 12c.07.665-.45 1.243-1.119 1.243H4.25a1.125 1.125 0 0 1-1.12-1.243l1.264-12A1.125 1.125 0 0 1 5.513 7.5h12.974c.576 0 1.059.435 1.119 1.007ZM8.625 10.5a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Zm7.5 0a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Z" />
              </svg>
              {totalItems > 0 && <span className={styles.cartCount}>{totalItems}</span>}
            </button>
          </div>
        </div>
      </header>

      {/* 2. Hero Section */}
      <section className={styles.hero}>
        <div className={`container ${styles.heroContent}`}>
          <h1 className={styles.heroTitle}>Premium Wholesale, Made Simple.</h1>
          <p className={styles.heroSubtitle}>
            Source bulk inventory instantly from verified regional distributors with real-time stock levels.
          </p>
        </div>
      </section>

      {/* 3. Catalog Section */}
      <main className="container" style={{ paddingBottom: '80px' }}>
        <div className={styles.sectionHeader}>
          <h2 className={styles.sectionTitle}>Wholesale Catalog</h2>
          <p className={styles.sectionSubtitle}>Minimum order quantities apply. Pricing shown in USD.</p>
        </div>

        {loading ? (
          <div className={styles.loader}>Loading wholesale items...</div>
        ) : products.length === 0 ? (
          <div className={styles.noResults}>
            <h3>No products found</h3>
            <p>Try resetting your search query or check back later.</p>
          </div>
        ) : (
          <div className={styles.grid}>
            {products.map((product) => (
              <div key={product.id} className="card">
                <div className={styles.cardHeader}>
                  <span className={styles.wholesalerBadge}>{product.wholesaler_name}</span>
                  {product.in_stock ? (
                    <span className="badge badge-success">In Stock</span>
                  ) : (
                    <span className="badge badge-error">Out of Stock</span>
                  )}
                </div>
                <div className={styles.cardBody}>
                  <h3 className={styles.productName}>{product.name}</h3>
                  <div className={styles.pricingRow}>
                    <div>
                      <span className={styles.label}>Wholesale Cost</span>
                      <p className={styles.price}>${product.wholesale_price.toFixed(2)}</p>
                    </div>
                    <div>
                      <span className={styles.label}>Available Qty</span>
                      <p className={styles.stock}>{product.stock_quantity} units</p>
                    </div>
                  </div>
                </div>
                <div className={styles.cardFooter}>
                  <button
                    className="btn btn-primary"
                    style={{ width: '100%' }}
                    onClick={() => addToCart(product, 1)}
                    disabled={!product.in_stock || product.stock_quantity <= 0}
                  >
                    {product.in_stock ? 'Add to Wholesale Order' : 'Unavailable'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Modals & Drawers */}
      <AuthModal isOpen={isAuthOpen} onClose={() => setIsAuthOpen(false)} />
      <CartDrawer onOpenAuth={() => setIsAuthOpen(true)} />
    </div>
  );
}
